import { SCALE_FALLBACK_COLOR } from '../constants.js';
import { getValidColor } from './getValidColor.js';
import {
  type ColorPalette,
  type ColorToken,
  type CustomColorPalette,
  isCustomColorPalette,
  isCustomColorRecordPalette,
  shouldApplyAutomatically,
  type ColorPaletteMode,
} from '../types/color-palette.js';
import {
  automaticColoringMap,
  colorPaletteMap,
} from '../types/color-palettes-definitions.js';

function getCustomRecordColor(
  name: string,
  colorPalette: Record<string, string>,
  defaultColor: string,
) {
  const lowerCasedName = name.toLowerCase();
  const colorKey =
    Object.keys(colorPalette).find(
      (key) => key.toLowerCase() === lowerCasedName,
    ) ?? '';
  const color = colorPalette[colorKey];

  return { Default: getValidColor(color, defaultColor) };
}

/**
 * Decides whether to assign a default palette or a custom one
 * @param name - name of the category as string
 * @param index - position of the category name
 * @param colorPalette - type of palette being passed in
 * @returns The proper color palette to be assigned
 */
export const getColorPalette = (
  name: string,
  index: number,
  colorPalette: ColorPalette | CustomColorPalette,
  colorPaletteMode: ColorPaletteMode = 'multi-color',
): ColorToken => {
  // Object OR Array
  if (isCustomColorPalette(colorPalette)) {
    // Object
    if (isCustomColorRecordPalette(colorPalette)) {
      return getCustomRecordColor(
        colorPaletteMode === 'single-color'
          ? Object.keys(colorPalette)[0]
          : name,
        colorPalette,
        SCALE_FALLBACK_COLOR,
      );
    }

    // Array
    return {
      Default:
        colorPalette[index % colorPalette.length] ?? SCALE_FALLBACK_COLOR,
    };
    // Predefined color palette OR automatic color palette
  } else {
    const colorPaletteTokenMap: Record<string, ColorToken> =
      colorPaletteMap[colorPalette];
    const paletteKeys = Object.keys(colorPaletteTokenMap);
    const palette = paletteKeys[index % paletteKeys.length];

    if (shouldApplyAutomatically(colorPalette)) {
      const colorMap: Record<string, string> =
        automaticColoringMap[colorPalette];

      return getCustomRecordColor(
        colorPaletteMode === 'single-color' ? '' : name,
        colorMap,
        colorPaletteTokenMap[palette].Default,
      );
    }

    return colorPaletteTokenMap[palette];
  }
};
